import { useEffect, useState } from 'react';
import styles from './style.module.css';


export const SideBox = () => {

    const [selectedItem, setSelectedItem] = useState(1);

    const changeScrollOffset = (offset: number) => {
        window.scrollTo(0, offset?offset+200:0);
    }

    const handleScroll = () => {
        const doc = window.document.body;
        const scrollTop = (window.pageYOffset || doc.scrollTop)  - (doc.clientTop || 0);
        console.log(scrollTop);
        
        changeMenuState(scrollTop);
    }

    const changeMenuState = (scrollOffset: number) => {
        if (scrollOffset < 400) {
            setSelectedItem(1);
        }
        else if (scrollOffset >= 400 && scrollOffset < 1200) {
            setSelectedItem(2);
        }
        else if (scrollOffset >= 1200 && scrollOffset < 2350) {
            setSelectedItem(3);
        }
        else if (scrollOffset >= 2350) {
            setSelectedItem(4);
        }
    }

    useEffect(() => {
        window.addEventListener('scroll', handleScroll);
    }, [])

    return (
        <div className={styles.side_box}>
            <div onClick={() => changeScrollOffset(0)} className={selectedItem == 1 ? `${styles.side_box_item} ${styles.active}` : `${styles.side_box_item}`}><div className={styles.side_box_item_title}>brief</div></div>
            <div onClick={() => changeScrollOffset(400)} className={selectedItem == 2 ? `${styles.side_box_item} ${styles.active}` : `${styles.side_box_item}`}><div className={styles.side_box_item_title}>skills</div></div>
            <div onClick={() => changeScrollOffset(1200)} className={selectedItem == 3 ? `${styles.side_box_item} ${styles.active}` : `${styles.side_box_item}`}><div className={styles.side_box_item_title}>work history</div></div>
            <div onClick={() => changeScrollOffset(2350)} className={selectedItem == 4 ? `${styles.side_box_item} ${styles.active}` : `${styles.side_box_item}`}><div className={styles.side_box_item_title}>projects</div></div>
        </div>
    )    
}